export const dzQuestions = [
  { type: "qcm", theme: "Cuisine", level: 1, question: "Je suis un plat délicieux à base de semoule cuite à la vapeur, généralement servi avec des légumes et de la viande. Bien que souvent présenté en grande quantité, vous ne pourrez résister à l'envie d'en reprendre encore et encore. Suis-je:", options: ["Taboulé", "Salade de quinoa", "Le couscous"], answer: "Le couscous" },
  { type: "jesuis", theme: "Cuisine", level: 2, question: "Je suis une boisson brune au goût de pomme et de caramel qui est profondément enracinée dans l'identité patrimoniale de l'Algérie. Comment suis-je appelé aujourd'hui ?", answer: "Hamoud Boualem - SELECTO" },
  { type: "jesuis", theme: "Cuisine", level: 3, question: "Comment s'appelle le plat de riz d'origine de l'est de l'Algérie, surnommé \"langues d'oiseaux à l'Algérienne\" ?", answer: "Le Tlitli chaoui" },
  { type: "qcm", theme: "Cuisine", level: 1, question: "Quel est le nom des crêpes berbères traditionnelles, qui sont faites en empilant des couches de pâte fine les unes sur les autres ?", options: ["Mille-feuille", "Mleoui", "Msemen"], answer: "Msemen" },
  { type: "jesuis", theme: "Cuisine", level: 2, question: "Quelle est la marque de chocolat noir la plus ancienne et l'une des plus anciennes et des plus  appréciées en Algérie ?", answer: "Chocolat \"Ambassadeur\"" },
  { type: "jesuis", theme: "Cuisine", level: 3, question: "Quel est le nom de la spécialité culinaire des Constantinois, préparée à base de pâtes carrées très fines et souvent consommée lors du Al Mawlid ?", answer: "La Trida constantinoise" },
  { type: "qcm", theme: "Cuisine", level: 1, question: "De quel nom désigne-t-on le beignet qui est préparé avec une pâte levée et de la semoule très fine, qui est longuement pétrie et qui a l'apparence d'une éponge une fois cuit ?", options: ["Sfendj", "Bourek", "Soussta"], answer: "Sfendj" },
  { type: "jesuis", theme: "Cuisine", level: 2, question: "Je suis un fruit largement consommé et très populaire, cultivé principalement dans le Sahara en Algérie. Je suis la variété la plus connue à travers le monde. Pouvez-vous deviner qui je suis ?", answer: "Deglet Nour" },
  { type: "jesuis", theme: "Cuisine", level: 3, question: "Quel est le fruit résultant du croisement naturel entre la mandarine et l'orange, originaire d'Algérie ?", answer: "La Clémentine, a vu le jour près d'Oran en 1902." },
  { type: "qcm", theme: "Cuisine", level: 1, question: "Pouvez-vous expliquer ce qu'est le  Makroudh ?", options: ["Une pâtisserie à base de semoule fourrée aux dattes et frite", "Une crème aux fruits secs", "Une salade de fruits"], answer: "Une pâtisserie à base de semoule fourrée aux dattes et frite" },
  { type: "jesuis", theme: "Cuisine", level: 2, question: "De quelle spécialité culinaire d'Alger parle-t-on ? Elle est composée de pâtes fines, de poulet et de navets, et est généralement servie avec une sauce aromatisée à la cannelle. Pouvez-vous identifier cette spécialité ?", answer: "La Rechta" },
  { type: "jesuis", theme: "Cuisine", level: 3, question: "Quel est le nom du gâteau traditionnel algérien, léger et spongieux, ressemblant à une génoise?", answer: "Le Mouskoutchou" },
  { type: "qcm", theme: "Cuisine", level: 1, question: "Pourriez-vous me dire ce que représente Dolma?", options: ["Un pain traditionnel algérien à base de semoule", "une recette de légumes farcis en sauce", "Une soupe à base de pois chiches"], answer: "une recette de légumes farcis en sauce" },
  { type: "jesuis", theme: "Cuisine", level: 2, question: "Je suis un mets traditionnel constitué de pâtes en forme de gros grains de couscous, pouvant être agrémenté de divers légumes ainsi que de viande séchée appelée \"Khlea\".", answer: "Le Berkoukes" },
  { type: "jesuis", theme: "Cuisine", level: 3, question: "Comment se nomme le plat algérien à base de farine de pois chiche, d'origine hispano-oranaise ?", answer: "Garantita" },
  { type: "qcm", theme: "Cuisine", level: 1, question: "De quelle soupe s'agit-il? Elle est principalement consommée pendant le mois du Ramadan, et préparée avec du blé concassé, de la viande et une touche de citron ?", options: ["Chorba Fric", "La Rechta", "Tajine zitoune"], answer: "Chorba Fric" },
  { type: "jesuis", theme: "Cuisine", level: 2, question: "Je suis une douceur algérienne qui marie les saveurs de l'amande ou des noix avec un glaçage sucré qui me donne une texture lisse et brillante. On peut me trouver sous différentes formes.", answer: "M'khabez" },
  { type: "jesuis", theme: "Cuisine", level: 3, question: "Quel est le nom du pain traditionnel des Touaregs, cuit sous la cendre dans le désert ?", answer: "La taguella" },
  { type: "qcm", theme: "Cuisine", level: 1, question: "Pouvez-vous me dire quel est ce plat délicieux mais simple, principalement préparé avec des pommes de terre et de la Darsa ?", options: ["Baghrir", "Chtitha Balata", "Tikourbabine"], answer: "Chtitha Balata" },
  { type: "jesuis", theme: "Cuisine", level: 2, question: "Je suis un délicieux gâteau en forme de croissant de lune, préparé avec de la pâte d'amande parfumée à la fleur d'oranger et saupoudré de sucre glace.", answer: "La Tcharek  (Corne de gazelle), c'est comme une petite bouchée de bonheur en bouche" },
  { type: "jesuis", theme: "Cuisine", level: 3, question: "Quel est le nom de la boisson légèrement sucrée, à base de café et considérée comme l'ancêtre du café glacé ?", answer: "Mazagran café" },
  { type: "qcm", theme: "Cuisine", level: 1, question: "Pourriez-vous me dire ce que représente  la Chakchouka ?", options: ["Un plat à base d'œufs, poivrons et de tomates", "Une soupe de poisson", "Un mélange d'épices"], answer: "La Chakchouka est un plat à base d'œufs et de tomates, souvent agrémenté de poivrons et d'épices" },
  { type: "jesuis", theme: "Cuisine", level: 2, question: "Je suis l'un des sandwichs les plus populaires et les plus consommés en Algérie, particulièrement apprécié par les étudiants.", answer: "Le sandwich frites-omelette" },
  { type: "jesuis", theme: "Cuisine", level: 3, question: "Quelle est la pâte traditionnelle \"Vermicelles de l'est\", originaire de Constantine et Annaba, préparée pour le Muharram ?", answer: "la Gritiliya" },
  { type: "qcm", theme: "Cuisine", level: 1, question: "Pouvez-vous me dire quel est le dessert algérien traditionnel, un des  plus renommés, préparé avec du miel et des fruits secs pour apporter une texture croustillante ?", options: ["Baklava", "Basboussa", "Baba au rhum"], answer: "Baklava" },
  { type: "jesuis", theme: "Cuisine", level: 2, question: "Je suis une soupe classique préparée à base de tomates, de légumes, de viande et d'oignons. Parmi les soupes les plus appréciées de l'Oranie, je suis considérée comme la seconde plus populaire après la chorba.", answer: "Harira - La Harira au goût délicieux qui met en joie tes narines" },
  { type: "jesuis", theme: "Cuisine", level: 3, question: "Quel est le nom du sirop composé d'eau, d'eau de fleur d'oranger, de sucre et de cannelle, une boisson traditionnelle algérienne servie fraîche ?", answer: "Cherbet" },
  { type: "qcm", theme: "Cuisine", level: 1, question: "Quel est le nom de la sucrerie qui a un goût de caramel et de chocolat et qui est une des friandises préférées de tous les enfants algériens ?", options: ["Flash", "Caprice", "Bimo"], answer: "Caprice" },
  { type: "jesuis", theme: "Cuisine", level: 2, question: "Je suis une variante différente du couscous, largement appréciée dans toute l'Algérie. On me sert généralement sans sauce, accompagné de semoule et de raisins secs, et je suis souvent accompagné d'un verre de L'ben.", answer: "Le Mesfouf- Un mélange sucré-salé, un pur délice sans être prétentieux" },
  { type: "jesuis", theme: "Cuisine", level: 3, question: "Quel est l'autre nom de la pâtisserie algérienne appelée Charia dans l'Ouest et \"H'rissa\" dans l'Est de l'Algérie ?", answer: "Kalb el Louz. C'est croquant, c'est fondant, c'est tout simplement divin." },
  { type: "qcm", theme: "Cuisine", level: 1, question: "Quel est le nom des galettes algériennes composées de semoule et de beurre, et souvent arrosées de miel ?", options: ["Kesra", "Mlaoui", "Mbesses"], answer: "Mbesses" },
  { type: "jesuis", theme: "Cuisine", level: 2, question: "Je suis un plat traditionnel de l'ouest de l'Algérie, préparé avec de la viande de mouton ou d'agneau, agrémenté d'abricots ou de nèfles, et parfumé avec du safran et de la fleur d'oranger.", answer: "La Mechmachia Mâamra" },
  { type: "jesuis", theme: "Cuisine", level: 3, question: "Quel est le nom de la pâtisserie traditionnelle algéroise, signifiant \"épineux\" en argot, et surmontée d'une cerise rouge confite ?", answer: "Mchewek" },
  { type: "qcm", theme: "Cuisine", level: 1, question: "Pouvez-vous me dire de quel dessert algérien il s'agit, qui se présente sous forme de crêpes avec de nombreux petits trous et est généralement servi avec du miel ?", options: ["Les crêpes de l'amitié", "Mchawcha", "Baghrir"], answer: "Baghrir" },
  { type: "jesuis", theme: "Cuisine", level: 2, question: "Je suis un plat originaire d'Alger, élaboré à partir de boulettes de viande de boeuf relevées d'ail, de cumin et de viande d'agneau.", answer: "Mtewem. Ce trésor culinaire et plat délicieux, aux senteurs de l'Orient." },
  { type: "jesuis", theme: "Cuisine", level: 3, question: "Quel est le fromage traditionnel à base de lait de chèvre ou de brebis, originaire de l'est de l'Algérie dans les régions de l'Aurès ?", answer: "Le Bouhezza" },
  { type: "qcm", theme: "Cuisine", level: 1, question: "Pouvez-vous me donner le nom de la salade algérienne faite avec des poivrons et des tomates grillés, et assaisonnée d'huile d'olive ?", options: ["Chtitha", "Hmiss", "Aghroum"], answer: "Hmiss" },
  { type: "jesuis", theme: "Cuisine", level: 2, question: "Je suis un mets préparé à partir de foie d'agneau ou de mouton, accompagné d'une sauce composée de tomates, d'ail, de persil, de coriandre et de cumin.", answer: "Kebda Mchermla" },
  { type: "jesuis", theme: "Cuisine", level: 3, question: "Quel est le fromage traditionnel algérien originaire de Ghardaïa et Naâma, fabriqué à base de lait de chèvre selon des procédés traditionnels ?", answer: "Le Takemarit, ou el Kemmariya" },
  { type: "qcm", theme: "Cuisine", level: 1, question: "Pourriez-vous me dire ce que représente le Brik ?", options: ["Une feuille souple de blé fourrées aux œufs, fromage et viande", "Un mijoté de viande et de légumes", "Une soupe de pois chiches"], answer: "Une feuille souple de blé fourrées aux œufs, fromage et viande" },
  { type: "jesuis", theme: "Cuisine", level: 2, question: "Je suis un plat algérois traditionnel, conçu pour éviter le gaspillage alimentaire. Je suis préparé à base de pain rassis, de chapelure, d'oignons, de pois chiches et de poulet, et je suis servi avec une sauce blanche.", answer: "Sfiria, du bonheur à chaque bouchée" },
  { type: "jesuis", theme: "Cuisine", level: 3, question: "Comment se nomme la soupe de fèves souvent servie avec de l'huile d'olive et du cumin en Algérie ?", answer: "Bissara" },
  { type: "qcm", theme: "Cuisine", level: 1, question: "Pourriez-vous me dire ce que représente  la Chorba ?", options: ["Une soupe épicée à base de viande et de légumes", "Un plat de poisson grillé", "Une salade de légumes"], answer: "La Chorba est une soupe épicée très populaire en Algérie, à base de viande, de légumes et d'épices" },
  { type: "jesuis", theme: "Cuisine", level: 2, question: "Je suis un type de pain traditionnel algérien, originaire de l'Est de l'Algérie et également populaire en Tunisie. Je suis fait de semoule et je prends la forme d'une galette. On peut me consommer seul ou accompagné de tartinades comme du beurre, de la confiture ou du miel.", answer: "Kesra" },
  { type: "jesuis", theme: "Cuisine", level: 3, question: "Quel est le nom de l'entrée chaude traditionnelle originaire de M'sila et très répandue à Bou Saada en Algérie ?", answer: "Zviti" },
  { type: "qcm", theme: "Cuisine", level: 1, question: "Pourriez-vous me dire ce que représente  Khlea ?", options: ["Une viande séchée et conservée dans de l'huile d'olive", "Une soupe de lentilles", "Un dessert à base de semoule et de lait"], answer: "Une viande séchée et conservée dans de l'huile d'olive" },
  { type: "jesuis", theme: "Cuisine", level: 2, question: "Je suis une pâtisserie découpée en rectangles avec des entailles réalisées à l'aide d'une roulette, puis habilement enchevêtrée, frite, trempée dans du miel et enfin saupoudrée de graines de sésame.", answer: "Le Griouech, une fois que vous y avez goûté, vous ne pouvez plus vous en passer." },
  { type: "jesuis", theme: "Cuisine", level: 3, question: "Quel est le gâteau algérien à base d'amandes, de sirop de sucre, de chapelure et parfumé à l'eau de fleur d'oranger ?", answer: "Khobz el bey" },
  { type: "qcm", theme: "Cuisine", level: 1, question: "Pourriez-vous me dire ce que représente  Zlabia ?", options: ["Une pâtisserie frite en forme de spirale", "Une pâtisserie frite en forme de losange", "Un plat traditionnel souvent prépare pendant le ramadan"], answer: "Zlabia est une pâtisserie traditionnelle algérienne, frite en forme de spirale et recouverte de miel" },
  { type: "jesuis", theme: "Cuisine", level: 2, question: "Je suis un plat culinaire algérien qui consiste en un mouton ou un agneau entier rôti lentement à la broche sur un feu de bois.", answer: "Méchoui" },
  { type: "jesuis", theme: "Cuisine", level: 3, question: "Quel est le nom du sablé à base de farine, souvent servi avec du café ou du thé à la menthe lors des fêtes, notamment lors de l'Aïd ?", answer: "Ghribiya. Une fois qu'on y goûte, on devient vite accro." },
  { type: "qcm", theme: "Cuisine", level: 1, question: "Pouvez-vous me dire de quel entremets Algérian il s'agit ? Il est décrit comme ayant une texture pâteuse et est composé de semoule torréfiée, de miel, de fleur d'oranger et de beurre fondu.", options: ["Mesfouf", "La Tamina,", "La M'Khanfa"], answer: "La Tamina," },
  { type: "jesuis", theme: "Cuisine", level: 2, question: "Quelle est cette boisson naturelle traditionnelle réhydratante extraite du palmier dattier et très consommée dans la région du Sahara?", answer: "Le Legmi ou sève de palmier" },
  { type: "jesuis", theme: "Cuisine", level: 3, question: "Comment se nomme le plat de viande mijoté aux épices et aux fruits secs, souvent servi lors des grandes occasions dans l'ouest de l'Algérie ?", answer: "La Mouna" },
  { type: "qcm", theme: "Cuisine", level: 1, question: "Pouvez-vous me dire quel est le plat traditionnel algérien contenant principalement des morceaux de poulet, des olives, des oignons, des carottes et du jus de citron ?", options: ["L'Ham Lahlou", "Mkhabez", "Tajine Zitoune"], answer: "Tajine Zitoune" },
  { type: "jesuis", theme: "Cuisine", level: 2, question: "Je suis une pâtisserie algérienne faite de pâte de farine remplie d'une farce d'amandes parfumée au zeste de citron. Après la cuisson, je suis trempée dans une préparation de miel et d'eau de fleur d'oranger.", answer: "Dziriettes" },
  { type: "jesuis", theme: "Cuisine", level: 3, question: "Comment s'appelle ce petit beignet à base de pommes de terre qui est généralement servi nature mais peut également être fourré ?", answer: "La Maakouda" },
  { type: "qcm", theme: "Cuisine", level: 1, question: "Quel est le nom du mélange d'ail, d'épices et de condiments souvent utilisé en cuisine algérienne, qui est réduit en purée à l'aide d'un mortier ?", options: ["Mhencha", "Darsa", "Loukoum"], answer: "Darsa" },
  { type: "jesuis", theme: "Cuisine", level: 2, question: "Je représente un plat anti-gaspillage de la cuisine algérienne et maghrébine, préparé à partir de la tête et d'autres parties de mouton ou d'agneau. Cette recette est souvent réalisée lors de l'Aïd el-Kébir.", answer: "Bouzelouf" },
  { type: "jesuis", theme: "Cuisine", level: 3, question: "Quel est le nom du plat à base de viande de mouton, de pruneaux, de cannelle et d'eau de fleur d'oranger, servi durant le Ramadan et lors des fêtes de mariage ?", answer: "Le Lham Hlou" },
  { type: "qcm", theme: "Arts & Culture", level: 1, question: "Quel est le nom du très célèbre tableau d'Eugène Delacroix, qui a inspiré la série de quinze peintures \"Les Femmes d'Alger\" du Pablo Picasso ?", options: ["Regard interdit, son coupé!", "Femmes d'Alger dans leur appartement", "Dans la Casbah, j'ai revu les femmes d'Alger"], answer: "Femmes d'Alger dans leur appartement" },
  { type: "jesuis", theme: "Arts & Culture", level: 2, question: "Qui suis-je? Je suis un écrivain algérien et le fondateur de la première Union des écrivains algériens (U.E.A). Mon roman éponyme, L'Opium et le Bâton, a été publié en 1965.", answer: "Mouloud Mammeri" },
  { type: "jesuis", theme: "Arts & Culture", level: 3, question: "Connaissez-vous le nom de cet artisanat qui éblouit les passionnés d'art et d'architecture mauresques et qui fait l'objet d'une convoitise effrénée. Et devinez qui s'en inspire pour sa nouvelle collection ? La marque Adidas a réalisé un maillot de sport pour l'équipe nationale algérienne.", answer: "Zellige" },
  { type: "qcm", theme: "Arts & Culture", level: 1, question: "Quel est le nom de l'écrivain, romancier,  nouvelliste né en Algérie et qui a remporté le prix Nobel de littérature en 1957?", options: ["Albert Camus", "Tahar Djaout", "Albert Memmi"], answer: "Albert Camus" },
  { type: "jesuis", theme: "Arts & Culture", level: 2, question: "Qui suis-je? Je suis un écrivain algérien renommé pour ma trilogie de livres consacrée à l'Algérie. Mon parcours littéraire a commencé avec la sortie de mon premier roman, intitulé \"La Grande Maison\".", answer: "Mohamed Dib" },
  { type: "jesuis", theme: "Arts & Culture", level: 3, question: "Qui est le célèbre peintre algérien considéré comme l'un des fondateurs de l'art moderne et de la peinture algérienne contemporaine ?", answer: "Mohammed Khadda" },
  { type: "qcm", theme: "Arts & Culture", level: 1, question: "Pouvez-vous me donner le nom d'un des plus grands et plus anciens musées d'art d'Afrique, qui se trouve dans le quartier du Hamma du côté du Jardin d'Essai à Alger ?", options: ["Le musée municipal d'Alger", "Le musée national des Beaux-Arts d'Alger", "Le musée national de l'art contemporain"], answer: "Le musée national des Beaux-Arts d'Alger" },
  { type: "jesuis", theme: "Arts & Culture", level: 2, question: "Qui suis-je? Je suis une actrice franco-algérienne en pleine ascension sur la scène cinématographique française. J'ai participé à des films renommés tels que Papicha, Nos Frangins et Les Trois Mousquetaires.", answer: "Lyna Khoudri" },
  { type: "jesuis", theme: "Arts & Culture", level: 3, question: "Qui est l'artiste algérien appartenant à la génération pionnière de la peinture algérienne moderne ? Célèbre pour ses toiles abstraites aux teintes vibrantes, ses créations s'inspirent fréquemment de la culture locale et des panoramas naturels de l'Algérie.", answer: "Mohamed Aksouh" },
  { type: "qcm", theme: "Arts & Culture", level: 1, question: "Compléter le proverbe suivant: Yaghati chems bel ...", options: ["Tgheti chems bel ghorbel", "Tgheti chems bel Kesskass", "Tgheti chems bel Kasskita"], answer: "Tgheti chems bel ghorbel" },
  { type: "jesuis", theme: "Arts & Culture", level: 2, question: "Qui suis-je? Je suis un écrivain algérien renommé, reconnu pour mon célèbre roman \"Nedjma\" ainsi que pour avoir interpellé Albert Camus au sujet de l'absence de personnages algériens dans ses écrits.", answer: "Kateb Yacine" },
  { type: "jesuis", theme: "Arts & Culture", level: 3, question: "Quelle est la célèbre peintre algérienne, faisant partie de la génération de 1930, mondialement connue pour ses gouaches et signant ses œuvres de son prénom usuel, qui a été l'une des fondatrices de l'art pictural algérien moderne ?", answer: "Baya, de son vrai nom Fatma Haddad" },
  { type: "qcm", theme: "Arts & Culture", level: 1, question: "Compléter le proverbe suivant: Sal el moudjareb ...", options: ["Sal el moudjareb ouala tsal Jarek", "Sal el moudjareb ouala tsal Ettbib", "Sal el moudjareb ouala tsal El kbir"], answer: "Sal el moudjareb ouala tsal Ettbib" },
  { type: "jesuis", theme: "Arts & Culture", level: 2, question: "Qui suis-je ? Je suis une chaussure de la marque Adidas, devenue un symbole pour les jeunes algériens dans les années 90 et associée à la date d'octobre 88 dans les caricatures de célèbres dessinateurs algériens Le Hic ou Dilem.", answer: "les Stan Smith" },
  { type: "jesuis", theme: "Arts & Culture", level: 3, question: "Qui a prononcé la célèbre citation : « Les musulmans vont en pèlerinage à la Mecque, les chrétiens au Vatican, et les mouvements de libération à Alger, Mecque des révolutionnaires » ?", answer: "Le guinéen Amilcar Cabral, fondateur du Parti africain pour l’indépendance de la Guinée et du Cap-Vert" },
  { type: "qcm", theme: "Arts & Culture", level: 1, question: "Compléter le proverbe suivant: Ma yaqâd fi ouad ...", options: ["Ma yaqâd fi ouad ghir Houtou", "Ma yaqâd fi ouad ghir Hbalou", "Ma yaqâd fi ouad ghir Hdjarou"], answer: "Ma yaqâd fi ouad ghir Hdjarou" },
  { type: "jesuis", theme: "Arts & Culture", level: 2, question: "Qui suis-je ? Je suis un réalisateur algérien de renom ayant à mon actif la réalisation de films tels que \"Omar Gatlato\" et \"Bab El Oued City\".", answer: "Merzak Allouache, parce qu'il est l'un des cinéastes les plus renommés d'Algérie" },
  { type: "jesuis", theme: "Arts & Culture", level: 3, question: "Comment s'appelle la pratique et tradition équestre très ancienne en Algérie, immortalisée par Nasreddine-Dinet, un des plus célèbres peintres orientalistes musulmans, consistant en la simulation d'assauts militaires ?", answer: "La Fantasia" },
  { type: "qcm", theme: "Arts & Culture", level: 1, question: "Que signifie le mot \"Hanouna\":", options: ["Il s'agit d'un terme qui se réfère à la belle-mère.", "C'est une désignation pour une personne désagréable.", "C'est une expression affectueuse pour dire \"mon amour, ma chérie\"."], answer: "C'est une expression affectueuse pour dire \"mon amour, ma chérie\"." },
  { type: "jesuis", theme: "Arts & Culture", level: 2, question: "Qui suis-je ? Je suis un écrivain algérien célèbre pour mon livre Meursault, contre-enquête, qui a remporté le prix Goncourt du premier roman en 2015.", answer: "Kamel Daoud" },
  { type: "jesuis", theme: "Arts & Culture", level: 3, question: "Quel est le nom du système d'irrigation traditionnel, situé dans les oasis du sud de l'Algérie, qui implique l'acquisition et la distribution d'eau ?", answer: "La foggara" },
  { type: "qcm", theme: "Arts & Culture", level: 1, question: "Compléter le proverbe suivant:  Ena n9olek sidi wenta", options: ["9oli madame", "9ader rouhek", "Aaref Qedrek"], answer: "Ana nqoulek sidi ouanta Aâref Qedrek" },
  { type: "jesuis", theme: "Arts & Culture", level: 2, question: "Qui suis-je ? Je suis une écrivaine algérienne très influente et célèbre, élue à l'Académie française en 2005 en devenant ainsi la première écrivaine africaine et du moyen orient à y être reçue.", answer: "Assia Djebar" },
  { type: "jesuis", theme: "Arts & Culture", level: 3, question: "Je suis un peintre algérien spécialisé en calligraphie arabe et en miniature, fondateur de l'École algérienne de miniature et né en 1896 à la Casbah d'Alger. Qui suis-je ?", answer: "Mohammed Racim" },
  { type: "qcm", theme: "Arts & Culture", level: 1, question: "Quelle est la signification du mot \"Intik\", qui est également le nom d'un célèbre groupe de rap algérien ?", options: ["Un mot qui veut dire \"je ne suis pas d'humeur\"", "Un garçon chétif", "Une expression populaire qui équivaut à \"ça va bien\"."], answer: "Une expression populaire qui équivaut à \"ça va bien\"." },
  { type: "jesuis", theme: "Arts & Culture", level: 2, question: "Je suis un artiste graphiste qui mélange le patrimoine algérien avec les codes du pop art mondial, de mon vrai nom \"Hicham Gaoua\". Qui suis-je ?", answer: "El Moustache" },
  { type: "jesuis", theme: "Arts & Culture", level: 3, question: "Je suis un peintre algérien spécialisé en calligraphie arabe et en miniature, fondateur de l'École algérienne de miniature et né en 1896 à la Casbah d'Alger. Qui suis-je ?", answer: "Mehdi Yades" },
  { type: "qcm", theme: "Arts & Culture", level: 1, question: "Quelle est la signification du terme \"Galou\" dans l'argot algérien ?", options: ["Très bon marché et peu coûteux", "Un tuyau d'arrosage", "Parle toujours, tu m'intéresses"], answer: "Très bon marché et peu coûteux" },
  { type: "jesuis", theme: "Arts & Culture", level: 2, question: "Qui suis-je ? Je suis une humoriste et animatrice algérienne et belge, ayant été révélée au grand public lors de mon passage au Jamel Comédie Club.", answer: "Nawal Madani" },
  { type: "jesuis", theme: "Arts & Culture", level: 3, question: "Je suis avocat et le mari de l'emblématique militante du FLN qui a été capturée, jugée et condamnée à mort par les militaires français durant la bataille d'Alger. Qui suis-je ?", answer: "Jacques Vergès" },
  { type: "qcm", theme: "Arts & Culture", level: 1, question: "Compléter le proverbe suivant:  ki techbea elkerch tqoul le", options: ["9alb thanna", "rass ghenni", "rouh nouth"], answer: "rass ghenni" },
  { type: "jesuis", theme: "Arts & Culture", level: 2, question: "Qui suis-je ? Je suis un acteur, humoriste et écrivain algérien, ayant écrit et joué dans le spectacle \"Djurdjurassique Bled\".", answer: "Mohand Fellag, dit Mohamed Fellag" },
  { type: "jesuis", theme: "Arts & Culture", level: 3, question: "Quel est le nom de l'acteur français d'origine algérienne connu pour son rôle dans la série télévisée française « Navarro » ?", answer: "Roger Hanin est connu pour son rôle dans la série télévisée \"Navarro\"." },
  { type: "qcm", theme: "Arts & Culture", level: 1, question: "Derrière la plume de cette jeune écrivaine algérienne dont le premier roman \"Captive\" a suscité l'émotion et la fascination des lecteurs à travers le monde, se cache qui ?", options: ["Inaam Kachachi", "Sarah Rivens", "Nawal El Saadawi"], answer: "Sarah Rivens" },
  { type: "jesuis", theme: "Arts & Culture", level: 2, question: "Qui suis-je ? Je suis un humoriste et acteur algérien (originaire de Tlemcen), me produisant sur scène dans des one-man-shows destinés à un public arabophone.", answer: "Abdelkader Secteur, de son vrai nom Abdelkader Arahman Rahmoun" },
  { type: "jesuis", theme: "Arts & Culture", level: 3, question: "Quel est le nom de l'acteur franco-algérien, champion de France de boxe thaïlandaise, passé par le Cours Florent et ayant incarné Primo dans James Bond, ainsi que tourné dans le clip du groupe « The Blase » ?", answer: "Dali Benssalah" },
  { type: "qcm", theme: "Arts & Culture", level: 1, question: "Pouvez-vous me donner le nom de l'actrice algérienne qui a joué dans divers films et sitcoms en Algérie, en Tunisie et en France ?", options: ["Biyouna", "Lala Khira", "Djamila Bouazza"], answer: "Biyouna" },
  { type: "jesuis", theme: "Arts & Culture", level: 2, question: "Qui suis-je ? Je suis un comédien algérien de théâtre pour enfants, connu pour avoir joué un personnage de clown dans l'émission pour enfants El Hadika Essahira (le jardin enchanté).", answer: "Hdidouane, de son vrai nom Mohamed Raouf Ikkache" },
  { type: "jesuis", theme: "Arts & Culture", level: 3, question: "Quel est le nom de la série à succès sur les banlieues, produit par Nawell, Madani, qui suscite à la fois l’engouement du public et des critiques ? Si la série est un véritable succès sur Netflix, sur la toile, les critiques ne s’arrêtent pas.", answer: "Jusqu’ici, tout va bien" },
  { type: "qcm", theme: "Arts & Culture", level: 1, question: "Pourriez-vous me dire la ville en Algérie où Yves Saint Laurent est né ? Pour vous aider, je peux vous dire qu'il est né dans un quartier nommé \"le plateau\".", options: ["Sidi Bel Abbès", "Mostaganem", "Oran"], answer: "Oran" },
  { type: "jesuis", theme: "Arts & Culture", level: 2, question: "Quel est la série télévisée algérienne, diffusé en 2023, qui a connu un succès retentissons avec plus de 60 millions de vues sur YouTube. Le synopsis de cette série se déroule dans le quartier populaire de Alger, Bab-el-Oued?", answer: "El Dama ou Ed'Dama" },
  { type: "jesuis", theme: "Arts & Culture", level: 3, question: "Comment s'appelle la reine berbère que les Touaregs du Hoggar considèrent comme leur propre reine? Son tombeau est un site historique à visiter dans le Hoggar et sa sépulture est conservée au musée du Bardo.", answer: "Tin Hinan" },
  { type: "qcm", theme: "Arts & Culture", level: 1, question: "Qu'est-ce que \"Haggar\" signifie en argot algérien ?", options: ["Référence au plus grand massif montagneux en Algérie", "Un plat traditionnel du Maghreb", "Une expression courante pour désigner quelqu'un qui s'attaque aux plus vulnérables"], answer: "Une expression courante pour désigner quelqu'un qui s'attaque aux plus vulnérables" },
  { type: "jesuis", theme: "Arts & Culture", level: 2, question: "Qui suis-je ? Je suis un acteur et humoriste algérien de mon vrai nom Ahmed Ayad, ayant joué dans de grands classiques du cinéma algérien tels que La Bataille d'Alger, Hassan Terro, L'Opium et le Bâton, etc.", answer: "Rouiched, de son vrai nom Ahmed Ayad" },
  { type: "jesuis", theme: "Arts & Culture", level: 3, question: "Quel est le nom de la principale fête locale à Djanet qui consiste en un affrontement rituel, sous la forme de musique et de danse? Cette fête ancestrale est en mémoire d'un pacte de paix.", answer: "S'biba." },
  { type: "qcm", theme: "Arts & Culture", level: 1, question: "Quel est le sens du mot \"Kheloui\" en argot algérien ?", options: ["Ce terme désigne une personne qui aime la vie et qui ne se prend pas la tête.", "C'est une expression courante utilisée pour décrire un criminel.", "Il s'agit d'un large champ de légumes."], answer: "Ce terme désigne une personne qui aime la vie et qui ne se prend pas la tête." },
  { type: "jesuis", theme: "Arts & Culture", level: 2, question: "Qui suis-je ?  Je suis un intellectuel algérien, écrivain, poète, romancier et journaliste, qui a été victime de la violence lors de la « décennie noire » en Algérie.", answer: "Tahar Djaout" },
  { type: "jesuis", theme: "Arts & Culture", level: 3, question: "Quel est le nom du pèlerinage qui se déroule dans le sud-ouest du Sahara algérien en commémoration de la naissance du prophète Mahomet? Durant ce pèlerinage, les mausolées des saints sont visités.", answer: "Le sbuâ, pèlerinage annuel à Gourara" },
  { type: "qcm", theme: "Arts & Culture", level: 1, question: "Pouvez-vous me donner la signification du terme \"Habes\" en argot algérien?", options: ["Cela signifie \"Jeune mondain\".", "Cela désigne une personne qui manque de savoir-vivre, un \"goujat\".", "Ce terme ne correspond pas à un sac de courses vintage."], answer: "Cela désigne une personne qui manque de savoir-vivre, un \"goujat\"." },
  { type: "jesuis", theme: "Arts & Culture", level: 2, question: "Qui suis-je ? Je suis un acteur Franco-Algérien, qui a remporté un Golden Globe Awards en 2022 pour mon rôle dans la mini-série \"The Serpent\" et qui a également joué dans le film \"Un prophète\".", answer: "Tahar Rahim" },
  { type: "jesuis", theme: "Arts & Culture", level: 3, question: "Comment s'appelle le célèbre peintre orientaliste, Franco-Algérien connu pour ses magnifiques peintures de la ville de Bou Saâda?", answer: "Étienne Dinet (devenu Nassr Eddine Dinet)" },
  { type: "qcm", theme: "Arts & Culture", level: 1, question: "Quelle est la signification du mot \"Hitiste\" dans l'argot algérien ?", options: ["Un artiste en herbe", "Une personne oisive", "Un mur ou le poteau d'un immeuble."], answer: "Une personne oisive" },
  { type: "jesuis", theme: "Arts & Culture", level: 2, question: "Qui suis-je ? Je suis l'auteur algérien Mohammed Moulessehoul, qui utilise le pseudonyme composé des deux prénoms de ma femme pour publier mes livres. Mes œuvres ont été traduites dans environ cinquante pays et ont également été adaptées pour le cinéma.", answer: "Yasmina Khadra" },
  { type: "jesuis", theme: "Arts & Culture", level: 3, question: "Quel est le nom du film qui relate les événements survenus dans cette région frontalière où le sang des deux peuples tunisien et algérien a été versé, unis dans un élan déterminé pour défendre leur indépendance et la liberté?", answer: "El Sakia" },
  { type: "qcm", theme: "Arts & Culture", level: 1, question: "Pourriez-vous me donner le nom de l'édifice imposant inauguré en 2016 à Alger, qui se distingue par son architecture remarquable et son importance culturelle ?", options: ["Le Ballet national d'Alger", "Théâtre national algérien", "L'Opéra d’Alger"], answer: "L'Opéra d’Alger" },
  { type: "jesuis", theme: "Arts & Culture", level: 2, question: "Je suis le musée algérien qui abrite dans mes murs une collection préhistoire et une collection ethnographie. Généralement, les objets préhistoriques proviennent des fouilles. J'ai été bâti à la fin du 18ème siècle par Hadj Ben Omar, un riche Tunisien exilé à Alger.", answer: "Le musée national du Bardo" },
  { type: "jesuis", theme: "Arts & Culture", level: 3, question: "Quel est le réalisateur algérien ayant réalisé le film \"Chronique des années de braise\" en 1975, qui est le seul film algérien à avoir obtenu la Palme d'or au Festival de Cannes ? Le film aborde la guerre d'indépendance algérienne.", answer: "Mohammed Lakhdar-Hamina." },
  { type: "qcm", theme: "Arts & Culture", level: 1, question: "L'Algérie possède un patrimoine culturel riche et une véritable diversité linguistique. Quelles sont les langues officielles de ce pays ?", options: ["Une seule langue: Arabe", "Deux langues: Arabe et Tamazight", "Trois langues: Arabe, Français et Tamazight"], answer: "Deux, l'arabe et Tamazight (ajouté à la constitution en 2016)" },
  { type: "jesuis", theme: "Arts & Culture", level: 2, question: "Je représente une tenue traditionnelle originaire de la ville de Tlemcen en Algérie. Le caftan en velours que je suis est orné de fils d'or, de perles de culture et de colliers. Cette tenue nuptiale symbolise le lien sacré qui unit les familles ainsi que la continuité entre les générations.", answer: "Chedda de Tlemcen" },
  { type: "jesuis", theme: "Arts & Culture", level: 3, question: "Quel est le nom de l'écrivain algérien d'expression française dont l'œuvre la plus célèbre est la trilogie Le Fils du pauvre, La Terre et le Sang et Les Chemins qui montent?", answer: "Mouloud Feraoun" },
  { type: "qcm", theme: "Histoire & Lieux", level: 1, question: "Pourriez-vous me donner le nom du premier président de l'Algérie indépendante ?", options: ["Ahmed Ben Bella", "Abdelaziz Bouteflika", "Chadli Bendjedid"], answer: "Ahmed Ben Bella" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 2, question: "Qui sommes-nous ? Nous sommes les frères, mandatés par le Sultan de Constantinople au début du XVIème siècle pour chasser les Espagnols des côtes algériennes.", answer: "Aroudj et kheir Eddine Barberousse" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 3, question: "Aux alentours de 800 avant J.C., quel peuple antique établi dans la région qui correspond approximativement au Liban actuel a créé de nombreux comptoirs commerciaux sur la côte algérienne ?", answer: "Les Phéniciens" },
  { type: "qcm", theme: "Histoire & Lieux", level: 1, question: "Pourriez-vous m'indiquer le nom de la guerre civile qui s'est déroulée dans les années 90 en Algérie ?", options: ["La guerre d'Algérie", "La guerre du Golfe", "La décennie Noire"], answer: "La décennie Noire" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 2, question: "Je suis Ali AMMAR, un combattant algérien du FLN qui a participé à la célèbre bataille d'Alger. On me connaît sous mon nom véritable, mais je suis également connu sous un surnom. Pouvez-vous deviner lequel ?", answer: "Ali la Pointe" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 3, question: "Durant les guerres puniques qui ont opposé Carthage à Rome, quel souverain berbère s'est emparé de Cirta (actuellement Constantine), qu'il a ensuite choisie comme capitale ?", answer: "Massinissa" },
  { type: "qcm", theme: "Histoire & Lieux", level: 1, question: "Pouvez-vous me dire le nom du fort édifié par les Espagnols à la fin du 16ème siècle sur les hauteurs du mont Murdjajo à Oran ?", options: ["Fort de Mahmoud", "Fort de Santa-Cruz", "Fort de Don Quichotte"], answer: "Fort de Santa-Cruz" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 2, question: "En tant que chef de la zone autonome d'Alger, je suis réputé pour mon réseau de bombes lors de la bataille d'Alger, me distinguant comme un combattant algérien de premier plan.", answer: "Yacef Saâdi" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 3, question: "Quel est le nom de cette reine berbère célèbre, qui était également une cheffe de guerre et une stratège militaire. Elle a  participé activement aux combats contre les conquérants  venus de la péninsule arabique.", answer: "La Kahina, Reine des Amazighs" },
  { type: "qcm", theme: "Histoire & Lieux", level: 1, question: "Pourriez-vous me donner le nom de la source thermale renommée pour sa source naturelle d'eau chaude à 44°C, située dans la wilaya de Sétif ?", options: ["Hammam Boussalem", "Hammam El hadj", "Hammam Guergour"], answer: "Hammam Guergour" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 2, question: "Je suis considéré comme l'un des plus anciens et remarquables « musées rupestres à ciel ouvert » au monde, à l'instar des fresques des aborigènes d'Australie ou des khoïsan de Namibie. Pouvez-vous me dire où je suis ?", answer: "Le parc culturel du Tassili n’ajjer" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 3, question: "En 647, sous la direction de qui les Arabes se sont-ils établis sous la bannière de l'Islam en Algérie ?", answer: "Okba Ibn Nafaa compagnon du Prophète" },
  { type: "qcm", theme: "Histoire & Lieux", level: 1, question: "Qui était le leader algérien qui a mené la lutte contre l'occupation française en 1830 ?", options: ["Emir Abdelkader", "Lalla Fatma N'Soumer", "El Mokrani"], answer: "Emir Abdelkader" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 2, question: "Je suis un magnifique palais historique algérois, situé dans la basse Casbah d'Alger, face à la mosquée Ketchaoua, et dont le nom proviendrait d'une princesse, fille du Dey d'Alger. Pouvez-vous me nommer ?", answer: "Dar Aziza" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 3, question: "Quel est le nom des moudjahidettes, ces combattantes de la cause algérienne mortes pour leur pays, également connues sous le nom de Filles du \"réseau bombe\" dans le film \"La Bataille d'Alger\" ?", answer: "Samia Lakhdari, Zohra Drif, Djamila Bouhired et Hassiba Ben Bouali" },
  { type: "qcm", theme: "Histoire & Lieux", level: 1, question: "Quelle est le nom de cette célèbre basilique, construite dans le style romano-byzantin et située sur un promontoire dominant la mer, à Bologhine, à l'ouest d'Alger?", options: ["L’abbaye de Staouëli", "Notre-Dame-d'Afrique", "Charles Lavigerie"], answer: "Notre-Dame-d'Afrique" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 2, question: "Je suis un lieu archéologique localisé dans une ancienne cité de la wilaya de Sétif, qui abrite l'un des plus remarquables ensembles de vestiges romains au monde. Pouvez-vous me nommer ?", answer: "Site de Djemila" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 3, question: "En raison de la pêche intensive et illégale, le Corail rouge, ou l'or rouge de la Méditerranée, est en danger d'extinction. Dans quelle ville d'Algérie ce corail est-il célèbre ?", answer: "El Kala - Situé à l’extrême est de l’Algérie" },
  { type: "qcm", theme: "Histoire & Lieux", level: 1, question: "Pourriez-vous me nommer cet édifice de style néo-mauresque, construit en 1910 à Alger, qui abrite les services de la poste algérienne au cœur de la ville d'Alger ?", options: ["Le Service postal d'Alger", "La Grande Poste d'Alger", "La Grande muraille d'Alger"], answer: "La Grande Poste d'Alger" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 2, question: "Je suis un monument emblématique situé à Alger. Mon nom signifie \"le tombeau du martyr\" en arabe. J'ai été construit en 1982 en l'honneur des combattants algériens morts lors de la guerre d'indépendance de l'Algérie. Qui suis-je ?", answer: "Maqam Echahid (Le mémorial du Martyr)" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 3, question: "Quel est le nom des dunes qui se trouvent dans le sud de la ville de Djanet, à Tadrart.  Considérées comme les plus hautes de cette région?", answer: "Les dunes de Tin Merzouga" },
  { type: "qcm", theme: "Histoire & Lieux", level: 1, question: "En quels mois et année le président algérien Ahmed Ben Bella a-t-il été accueilli en triomphe par les Cubains et leur leader Ernesto Che Guevara ?", options: ["En octobre 1962", "En octobre 1972", "En octobre 1982"], answer: "En octobre 1962" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 2, question: "On me surnomme la « Pompéi africaine ». Je suis situé au nord des Aurès et représente les ruines d'une cité romaine construite au Ier siècle. Qui suis-je ?", answer: "Les ruines de Timgad" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 3, question: "Quel lieu en Algérie a été inscrit au patrimoine mondial de l'UNESCO en 1982 pour son exemple parfait d'habitat traditionnel humain parfaitement adapté à l'environnement ?", answer: "La vallée du Mzab" },
  { type: "qcm", theme: "Histoire & Lieux", level: 1, question: "Quel est le nom de cet économiste de renom, conseillé par ses médecins pour entreprendre un voyage thérapeutique de plus de 3 mois en Algérie en 1882 afin de soigner ses soucis de santé ?", options: ["Adam Smith", "John Maynard Keynes", "Karl Marx"], answer: "Karl Marx" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 2, question: "Je suis une magnifique crique au sable orangé, située sur la Corniche d'or, l'une des plus belles portions du littoral algérien, entre Jijel et Béjaïa. Pouvez-vous me nommer ?", answer: "La plage rouge à Ziama Mansouriah (Jijel)" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 3, question: "Quel est le nom du mausolée numide datant du 3e siècle avant J.-C., situé en Algérie dans les Aurès, dans la wilaya de Batna ?", answer: "Mausolée du Medracen." },
  { type: "qcm", theme: "Histoire & Lieux", level: 1, question: "Quelle place porte le nom des combattants tombés pour la libération de l'Algérie durant la guerre d'indépendance ?", options: ["Place des Braves", "Place des Anciens", "Place des Martyrs"], answer: "Place des Martyrs" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 2, question: "Je suis l'une des plus grandes et plus belles mosquées d'Algérie, dotée d'une architecture originale, située dans la ville de Constantine. Qui suis-je ?", answer: "Emir Abdelkader Mosquée" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 3, question: "Quel est le site archéologique situé dans la wilaya de M'Sila, en Algérie, classé patrimoine mondial par l'UNESCO, qui abrite une Kalâa (« forteresse ») située à plus de 1 000 mètres d'altitude ?", answer: "Kalaa des Beni-Hammad" },
  { type: "qcm", theme: "Histoire & Lieux", level: 1, question: "Pouvez-vous me dire le nom de ce site antique situé à l'ouest d'Alger, en bord de mer, qui abrite des vestiges archéologiques tels que les thermes et l'amphithéâtre romains?", options: ["Ruines romaines de Zeralda", "Ruines romaines de Tipaza", "Ruines romaines de Djanet"], answer: "Ruines romaines de Tipaza" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 2, question: "Je suis un homme d'État, militaire, érudit religieux et commerçant algérien, dernier et très célèbre dey d'Alger de 1818 à 1830. Pouvez-vous me nommer ?", answer: "Hussein Dey" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 3, question: "Quel est le nom du complexe palatial royal, un exemple d'art mauresque et andalou situé à Tlemcen en Algérie et construit par les sultans zianides au 12ème siècle, symbole du pouvoir politique et témoin de la dynastie des Zianides ?", answer: "Le palais El Mechouar - Tlemcen" },
  { type: "qcm", theme: "Histoire & Lieux", level: 1, question: "Quel est le nom du plus grand massif montagneux du pays, situé dans le sud de l'Algérie ?", options: ["Massif de l'imzad", "Massif de Tamanrasset", "Massif du Hoggar"], answer: "Massif du Hoggar" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 2, question: "Je suis une ville du sud algérien surnommée « l'oasis rouge », également connue sous le nom de la ville des Ksour, où la fête du Gourara est célébrée chaque printemps.", answer: "Timimoun" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 3, question: "Quel est le nom de l'homme d'État et souverain berbère de la dynastie ziride qui fonda l'Alger actuelle, sous le nom d'El-Djazaïr ou Lezzayer, au milieu du 10e siècle ?", answer: "Bologhine ibn Ziri" },
  { type: "qcm", theme: "Histoire & Lieux", level: 1, question: "Quel événement survenu entre Hussein Dey et le consul français Pierre Deval le 30 avril 1827 est à l'origine de la déclaration de guerre du royaume de France à la régence d'Alger ?", options: ["L'affaire du bétail", "L'affaire de l'éventail", "L'affaire de la sandale"], answer: "L'affaire de l'éventail" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 2, question: "Je suis une ville belle et rebelle, considérée comme la première porte du Grand Sud algérien, une mer de dunes surnommée la « ville aux mille coupoles ».", answer: "El-Oued" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 3, question: "Quel est le nom officiel de la mosquée située dans la casbah d'Alger, connue sous le nom de Djamâa Li houd (ancienne grande synagogue d'Alger) ?", answer: "Djamâa Farès, mosquée Farès" },
  { type: "qcm", theme: "Histoire & Lieux", level: 1, question: "Le Palais des Raïs est l'un des monuments historiques les plus importants de la Casbah et de la ville d'Alger. Comment est-il également appelé ?", options: ["Bastion 7", "Bastion 17", "Bastion 23"], answer: "Bastion 23" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 2, question: "Je suis une oasis située à proximité de Djanet, dans le majestueux Parc culturel du Tassili n'Ajjer. Je suis entourée de paysages remarquables, tels que des dunes, des gorges  et des canyons spectaculaires. Ma beauté naturelle a inspiré de nombreux écrivains du monde entier.", answer: "L'oasis d'Essendilène" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 3, question: "Quelle est cette mosquée historique faisant partie du patrimoine mondial classé de l'UNESCO, située dans la basse casbah d'Alger et construite en 1436 ?", answer: "Mosquée Ketchaoua" },
  { type: "qcm", theme: "Histoire & Lieux", level: 1, question: "Quel est le nom de cette grotte située dans la commune de Belouizdad à Alger, où le célèbre écrivain espagnol s'est réfugié lors de sa captivité à Alger?", options: ["Grotte de Banderas", "Grotte de Cervantes", "Grotte d'Almodovar"], answer: "Grotte de Cervantes" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 2, question: "Je suis un cap algérien d'une splendeur indescriptible, niché au nord du port de Béjaïa. Mon phare, érigé à plus de 200 mètres de hauteur, est considéré comme l'un des phares les plus élevés de la mer Méditerranée et le phare naturel le plus haut du monde.", answer: "Le cap Carbon" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 3, question: "Quel est le nom de l'ancienne capitale ibadite surnommée la glorieuse pour sa prospérité, située à une dizaine de kilomètres de Ouargla et enfouie sous les dunes de sable jusqu'à ce qu'elle soit repérée grâce à la reconnaissance aérienne ?", answer: "Le site de Sedrata" },
  { type: "qcm", theme: "Histoire & Lieux", level: 1, question: "Comment s'appelle le documentaire sur l'Algérie produit par Yann Arthus Bertrand en 2015 ?", options: ["L'Algérie vue du ciel", "L'Algérie vue d'en bas", "Algérie, la Mecque des révolutionnaires"], answer: "L'Algérie vue du ciel" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 2, question: "Je suis une ancienne cité fascinante, au cœur du massif montagneux du Tassili n'Ajjer, connue sous le nom de \"ville des pierres\". Mon inscription au patrimoine mondial depuis 1982 témoigne de mon importance historique et culturelle en tant que  \"plus grand musée d'art préhistorique à ciel ouvert au monde\".", answer: "Séfar" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 3, question: "Comment appelle-t-on les ponts de Constantine, majestueux ouvrages d'art situés dans les gorges profondes de l'oued Rhumel, qui constituent les sujets les plus prisés des photographes de la ville ?", answer: "Les ponts d'El Kantara et Sidi M'Cid" },
  { type: "qcm", theme: "Histoire & Lieux", level: 1, question: "Dans quel endroit mythique d'Alger le premier film Tarzan a-t-il été tourné ?", options: ["Jardin d'essai d'el Hamma", "La grande mosquée", "La casbah d'Alger"], answer: "Jardin d'essai d'el Hamma" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 2, question: "Je suis cette ville envoûtante, située dans le grand sud, célèbre pour ma palmeraie luxuriante, mes habitations en terre rouge, mes gravures rupestres uniques. La réputation de l'hospitalité légendaire de mes habitants me précède. Je suis l'incarnation de l'enchantement.", answer: "Taghit" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 3, question: "Quel est le nom de ce site remarquable situé dans les Aurès, dans la wilaya de Batna, résultat spectaculaire du travail d'érosion du fleuve Abiod ?", answer: "Canyon du Ghoufi" },
  { type: "qcm", theme: "Histoire & Lieux", level: 1, question: "Pouvez-vous me donner le nom haut sommet d'Algérie, sa hauteur et sa localisation géographique ?", options: ["Mont Djura", "Mont Zina", "Mont Tahat"], answer: "Mont Tahat" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 2, question: "Je suis un parc national d'une beauté époustouflante, bordant la Méditerranée. Mes plages de sable fin, mes falaises majestueuses et mes paysages variés attirent de nombreux visiteurs. Mon statut de réserve de biosphère, décerné par l'UNESCO  témoigne de la richesse de ma biodiversité.", answer: "Parc national de Gouraya" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 3, question: "Quel est le nom de ce site touristique et religieux important, surnommé \"la ville de la montagne dominante\", situé dans la wilaya de Bordj Bou Arreridj ?", answer: "Bordj Zemoura" },
  { type: "qcm", theme: "Histoire & Lieux", level: 1, question: "Quel est le nom de la chaîne montagneuse située au nord de l'Algérie, constituant l'essentiel de la Petite Kabylie. Elle est séparée du Djurdjura par la vallée de la Soummam.", options: ["La chaîne Romaine", "La chaîne du Mzab", "La chaîne des Babors"], answer: "La chaîne des Babors" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 2, question: "Je suis un massif imposant, situé au cœur du Parc culturel du Tassili n'Ajjer. Mon inscription au patrimoine mondial de l'Unesco témoigne de ma valeur culturelle et historique. Mon paysage unique, composé de dunes colorées à couper le souffle et de peintures et de gravures rupestres exceptionnelles.", answer: "La Tadrart Rouge" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 3, question: "Quel est le nom de l'arc de triomphe romain érigé à l'emplacement de la porte occidentale des ruines romaines de Timgad ?", answer: "Arc de Trajean" },
  { type: "qcm", theme: "Histoire & Lieux", level: 1, question: "Les massacres de Sétif, Guelma et Kherrata sont des répressions sanglantes qui ont suivi des manifestations nationalistes, indépendantistes et anticoloniales qui ont eu lieu le ?", options: ["1 novembre 1954", "8 mai 1945", "5 juillet 1962"], answer: "8 mai 1945" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 2, question: "Je suis un mausolée vestige romain situé dans la wilaya de Tipaza en Algérie. Je suis un  tumulus de pierre d'environ 80 000 m3 et on me surnomme le Tombeau de la chrétienne.", answer: "Mausolée royal de Maurétanie" },
  { type: "jesuis", theme: "Histoire & Lieux", level: 3, question: "Quel est le nom de ce site archéologique situé dans la région du Tassili N'Ajjer, qui abrite une multitude d'abris ornés de plus de 5 000 gravures et peintures rupestres préhistoriques ?", answer: "Jabbaren" },
  { type: "qcm", theme: "Musique", level: 1, question: "Quel est le nom du chanteur algérien de raï, célèbre notamment pour son titre international \"Aicha\" ?", options: ["Cheb Mami", "Cheb Khaled", "Cheb Hasni"], answer: "Cheb Khaled" },
  { type: "jesuis", theme: "Musique", level: 2, question: "Je suis une émission emblématique de la télévision algérienne qui a été diffusée en 1991 et 1992. Je suis une véritable pépinière de talents pour de nombreux artistes en herbe, grâce à la production et à la réalisation d'Aziz Smati et Hakim Larouci.", answer: "Bled Music, bien plus qu'une simple émission de télévision, c'est une véritable pépinière de talents" },
  { type: "jesuis", theme: "Musique", level: 3, question: "Qui est le propriétaire emblématique de Disco Maghreb, le label légendaire de la musique raï ?", answer: "Boualem Benhaoua" },
  { type: "qcm", theme: "Musique", level: 1, question: "Pourriez-vous me citer le nom du chanteur algérien de raï, mondialement connu et célèbre notamment pour sa collaboration avec Sting sur le titre \"Désert Rose\" ?", options: ["Cheb Mami", "Cheb Khaled", "Rachid Taha"], answer: "Cheb Mami" },
  { type: "jesuis", theme: "Musique", level: 2, question: "Je suis un artiste adulé par la jeunesse pour mes chansons sentimentales qui ont inauguré le style \"raï love\". Avec plus de 150 albums à mon actif, je suis devenu l'idole des jeunes au Maghreb.", answer: "Cheb Hasni, prince du raï, a su chanter l'amour et la passion avec une voix unique qui a conquis les cœurs algériens et au-delà" },
  { type: "jesuis", theme: "Musique", level: 3, question: "Quel est le nom de l'artiste ayant interprété la célèbre chanson \"Djibouha ya laouled\" qui a marqué les esprits des supporters de football et qui continue de résonner dans les stades à ce jour ?", answer: "Sadek Djemaoui" },
  { type: "qcm", theme: "Musique", level: 1, question: "Quels artistes algériens ont interprété l'album mythique \"1, 2, 3 Soleils\" en 1998 ?", options: ["Cheb Mami, Rachid Taha et Cheb Khaled", "Cheb Khaled, Rachid Taha et Cheb Hasni", "Cheb Khaled, Rachid Taha et Faudel"], answer: "Cheb Khaled, Rachid Taha et Faudel" },
  { type: "jesuis", theme: "Musique", level: 2, question: "Originaire de la banlieue d'Alger, j'ai choisi mon nom d'artiste en hommage à un personnage de la célèbre série manga \"One Piece\". Mon premier succès, le morceau \"Guérilla\", m'a rapidement propulsé sur le devant de la scène.", answer: "Soolking, le maestro de la musique algérienne qui envoûte les foules avec ses rythmes enflammés" },
  { type: "jesuis", theme: "Musique", level: 3, question: "Quel est ce genre musical, qui combine poésie, chant polyphonique, musique et danse, est un symbole de la région du Sud Ouest Algérien. Il rassemble un joueur de bengri (flûte), un chanteur et un chœur.", answer: "L’Ahellil du Gourara" },
  { type: "qcm", theme: "Musique", level: 1, question: "Pouvez-vous m'indiquer le nom de l'instrument de musique largement répandu dans le Sahara, composé de deux paires de cliquettes de fer (cymbales) ?", options: ["L'harmonica", "Darbouka", "Qarqabu"], answer: "Qarqabu" },
  { type: "jesuis", theme: "Musique", level: 2, question: "Quel est le titre de cette chanson qui rend hommage aux sons et aux traditions de l'Ouest algérien et qui a été mise en avant dans un clip par la star mondiale de l'électro Dj Snake ?", answer: "Disco Maghreb" },
  { type: "jesuis", theme: "Musique", level: 3, question: "Quel est l'instrument de musique utilisé pour raconter l'histoire des Touaregs, dans le genre musical populaire qui est hautement apprécié par les habitants de l'Ahhagar et au-delà ?", answer: "L’imzad" },
  { type: "qcm", theme: "Musique", level: 1, question: "Quel est le nom du  groupe musical algérien de style Gnawa, créé par Amazigh Kateb, fils du célébre écrivain Algérien Kateb Yacine ?", options: ["Gnawa Distribution", "Gnawa Diffusion", "Gnawa Dimension"], answer: "Gnawa Diffusion" },
  { type: "jesuis", theme: "Musique", level: 2, question: "Je suis un type de musique dit \" populaire\" , qui a puise son inspiration dans  le vaste et immensément riche patrimoine de la musique Algérienne. Je sui interprété en dialecte de la capitale par des cheikhs (maîtres) et leurs orchestres?", answer: "Le Chaâbi" },
  { type: "jesuis", theme: "Musique", level: 3, question: "Quel fameux groupe de musique a interprété le tube \"Mouhal Omri Nansak\", qui a marqué et fait vibrer  les années 1980 ?", answer: "Polyphene" },
  { type: "qcm", theme: "Musique", level: 1, question: "De quelle émission s'agit-il, dont le principe est d'inviter des personnalités à bord d'une voiture, où on discute et chante ensemble, pendant que l'animateur conduit ?", options: ["Caracool Algérie", "Carpool Karaoké Algérie", "Djeraya Karaoké Algérie"], answer: "Carpool Karaoké Algérie" },
  { type: "jesuis", theme: "Musique", level: 2, question: "Je suis une icône féministe majeure dans l'histoire de la musique algérienne, surnommée la \"Reine du Raï\". Mon répertoire musical est l'un des plus riches en Afrique du Nord, avec pas moins de 200 morceaux.", answer: "Cheikha Rimitti - Saadia El Ghilizania" },
  { type: "jesuis", theme: "Musique", level: 3, question: "Qui est l'interprète du célèbre titre \"Hakmet leqdar\" ou encore \"Caravan to Baghdad\", dont le clip a été tourné dans le désert d'Almeria en Espagne ?", answer: "Hamid Baroudi" },
  { type: "qcm", theme: "Musique", level: 1, question: "Pouvez-vous me citer le nom de l'auteur-compositeur et musicien interprétant le générique de la série légendaire \"Nass Mlah City\" pour les saisons 1 et 3 ?", options: ["Baaziz", "Hassan Dj", "Magic System"], answer: "Baaziz" },
  { type: "jesuis", theme: "Musique", level: 2, question: "Nous sommes l'un des groupes de musique raï les plus populaires en Algérie. Originaires de Sidi Bel-Abbès, nous interprétons le célèbre morceau \"Ya Zina Diri Latay\".", answer: "Raïna Raï" },
  { type: "jesuis", theme: "Musique", level: 3, question: "Quelle chanteuse et mélomane, surnommée \"Le Rossignol de l'Est\", est considérée comme la grande dame du chant traditionnel constantinois et ambassadrice du Malouf ?", answer: "Fatima-Zohra Reggani" },
  { type: "qcm", theme: "Musique", level: 1, question: "Qui est l'auteur-compositeur-interprète de la chanson \"Ya Rayeh\", considérée comme l'un des titres les plus populaires du répertoire musical Algérien ?", options: ["El Hachemi Guerouabi", "El hadj en anka", "Dahmane el Harrachi"], answer: "Dahmane el Harrachi" },
  { type: "jesuis", theme: "Musique", level: 2, question: "Je suis une musique classique algérienne, héritière de la musique arabo-andalouse de l'école de Constantine. Mon genre musical est complexe et englobe plusieurs formes du chant traditionnel classique.", answer: "Le Malouf" },
  { type: "jesuis", theme: "Musique", level: 3, question: "Quel est le vrai nom d'Idir, le monument de la chanson Algérienne, chanteur, auteur-compositeur-interprète et musicien dont le tube \"A Vava Inouva\" est devenu célèbre dans le monde entier, diffusé dans de nombreuses langues ?", answer: "El Hamid Cheriet" },
  { type: "qcm", theme: "Musique", level: 1, question: "Au temps de la grande époque du raï, on surnommait cette chanteuse algérienne \"La diva\" ou encore \"La joyeuse\". De qui s'agit-il ?", options: ["Cheba Khira", "Cheba Zahouania", "Lala Zhore"], answer: "Cheba Zahouania" },
  { type: "jesuis", theme: "Musique", level: 2, question: "Je suis un genre musical populaire en Algérie qui s'inspire du Gharnati, le répertoire de musique arabo-andalouse de l'école de Tlemcen.", answer: "Le Hawzi" },
  { type: "jesuis", theme: "Musique", level: 3, question: "Quelle légende africaine, connue dans le monde entier sous le nom de \"Mama African\", a interprété \"Ifriqiya - Ana hourra fi Al Jazaier\" lors du premier festival culturel panafricain tenu à Alger ?", answer: "Miriam Makeba" },
  { type: "qcm", theme: "Musique", level: 1, question: "Quel est le nom de l'auteur du tube \"Zaâma Zaâma\", qui a connu un succès international ?", options: ["Cheb Abdou", "Hamid Baroudi", "Takfarinas"], answer: "Takfarinas" },
  { type: "jesuis", theme: "Musique", level: 2, question: "Je suis célèbre pour mes textes engagés et mes chansons, qui prônent une Algérie plurielle. On me surnomme le \"Rebel\". J'ai à mon actif pas moins de 28 albums et 224 chansons référencées.", answer: "Lounès Matoub" },
  { type: "jesuis", theme: "Musique", level: 3, question: "Quel est le nom du groupe touareg de Tamanrasset, dont les chansons \"Riwaya\" et \"Ligh Ezzaman\" sont célèbres pour leur genre musical alliant le rythme targui traditionnel et la musique occidentale ?", answer: "Tikoubaouine" },
  { type: "qcm", theme: "Musique", level: 1, question: "Comment s'appelle le festival culturel dont la scène principale est un théâtre ouvert sous forme d'arène romaine, se déroulant dans la wilaya de Batna ?", options: ["Le festival international de musique de Timgad", "Le festival international de musique de Tiaret", "Le festival international de musique de Tindouf"], answer: "Le festival international de musique de Timgad" },
  { type: "jesuis", theme: "Musique", level: 2, question: "Je suis une auteure-compositrice-interprète algéro-canadienne qui s'est fait connaître notamment avec le titre \"C'est chelou\", issu de mon premier album.", answer: "Zehira Darabid, dite Zaho" },
  { type: "jesuis", theme: "Musique", level: 3, question: "Quel est le nom du doyen de la musique DIWAN, qui a participé à plusieurs événements artistiques algériens, notamment à la conception de la bande originale du film \"La Bataille d'Alger\" (1966) ?", answer: "Mohamed Bahaz" },
  { type: "qcm", theme: "Musique", level: 1, question: "Qui est le chanteur algérien qui aborde les problèmes sociaux de la rue algérienne et auteur du célèbre titre \"Machafouhach\" ?", options: ["Moh L'Ancien", "Mouh Milano", "Mouh Sghir"], answer: "Mouh Milano" },
  { type: "jesuis", theme: "Musique", level: 2, question: "Je suis un groupe de rock algérien au style musical atypique, qui puise son inspiration à la fois dans le rock, le blues et les musiques traditionnelles algériennes.", answer: "Cheikh Sidi Bémol" },
  { type: "jesuis", theme: "Musique", level: 3, question: "Quel est le nom de la musique et de la danse traditionnelles guerrières de la tribu des Ouled Nhar de Sebdou (wilaya de Tlemcen) ? La gasba et le bendir sont les instruments de musique utilisés.", answer: "Le Nhari ou Dari" },
  { type: "qcm", theme: "Musique", level: 1, question: "Connaissez-vous le titre de la chanson de l'illustre chanteuse algérienne de musique chaâbi et hawzi, Naima Dziria?", options: ["Mazelni kima bekri", "Mazelni ala didani", "Mazelni bkedri ou chani"], answer: "Mazelni ala didani" },
  { type: "jesuis", theme: "Musique", level: 2, question: "Je suis un genre de musique inspiré de contes transmis oralement depuis une époque très lointaine, souvent considéré comme proche du châabi algérois, et qui est empreint de poésie.", answer: "La musique kabyle" },
  { type: "jesuis", theme: "Musique", level: 3, question: "Quel est le nom de ce style musical kabyle, sans instrument mais avec une forme mélodieuse, souvent chanté par des femmes pour exprimer des sentiments de joie ou de deuil ?", answer: "Achewiq" },
  { type: "qcm", theme: "Musique", level: 1, question: "Cheb Nasro, est considéré avec Cheb Hasni comme l'un des meilleurs chanteurs de raï sentimental. Pourriez-vous me citer le nom de son célèbre titre ?", options: ["Chira Ly Nabghiha", "Baida mon amour", "3tak rebi blassa fi Galbi"], answer: "3tak rebi blassa fi Galbi" },
  { type: "jesuis", theme: "Musique", level: 2, question: "Je suis un type de musique originaire d'Afrique subsaharienne, une musique spirituelle destinée à guérir les malades et chantée par un mâalem (maître musicien), utilisant comme instruments le guembri, le tambour et le qarqabus.", answer: "Le Gnawa" },
  { type: "jesuis", theme: "Musique", level: 3, question: "Quel est le nom de cette chanteuse algérienne, figure de proue de la musique Hawzi, dont la chanson principale est \"Mal Hbibi Malou\" ?", answer: "Fadhéla Dziria" },
  { type: "qcm", theme: "Musique", level: 1, question: "Mohamed Mazouni, ayant une carrière artistique de plus de cinquante ans, est l'auteur du titre atypique:", options: ["Khouk Travolta", "Boulevard Magenta", "Mouhal 3amri nenssak"], answer: "Khouk Travolta" },
  { type: "jesuis", theme: "Musique", level: 2, question: "Je suis un instrument de percussion largement répandu en Afrique du Nord, et plus particulièrement en Algérie. Je suis un tambour doté d'un cerclage en bois, et d'une peau de chèvre soigneusement collée sur tout le cadre.", answer: "Le bendir" },
  { type: "jesuis", theme: "Musique", level: 3, question: "Pourriez-vous m'indiquer l'auteur de cette chanson algérienne, qui a connu un succès retentissant dans les années 80 sous le nom de \"Goulili Ya Lalla\" ?", answer: "Tarcinas" },
  { type: "qcm", theme: "Musique", level: 1, question: "Qui est l'auteur du tube \"FARHI WE SAADI\", ayant connu un immense succès ?", options: ["Cheba Khira", "Hassiba Amrouche", "Rym Hakiki"], answer: "Hassiba Amrouche" },
  { type: "jesuis", theme: "Musique", level: 2, question: "Je suis cette artiste incontournable des fêtes familiales, qui a fait ses premiers pas dans le monde de la musique aux côtés de sa mère, elle-même artiste.", answer: "Hassiba Abderaouf" },
  { type: "jesuis", theme: "Musique", level: 3, question: "Quelle est l'identité de la chanteuse surnommée l'égérie Gnawi, originaire de Timimoun et membre du collectif Gaâda Diwan de Béchar ?", answer: "Aïcha Lebgaâ" },
  { type: "qcm", theme: "Musique", level: 1, question: "Pouvez-vous me donner le nom du groupe qui s'est fait connaître avec leur titre \"Zina\", repris par de nombreux autres artistes à travers le monde ?", options: ["El Dey", "Dziri style", "Babylone"], answer: "Babylone" },
  { type: "jesuis", theme: "Musique", level: 2, question: "Je suis cette star du Raï, qui a su se faire un nom dans le monde de la musique grâce à des titres tels que « Babor Li Jebni », « Ghorba » ou encore « Derja Derja ».", answer: "Cheb Bilal" },
  { type: "jesuis", theme: "Musique", level: 3, question: "Pouvez-vous m'indiquer le nom de l'artiste féminine algérienne, qui est sans nul doute une diva incontestée de la chanson arabe et qui a interprété les titres intemporels \"Batwanes Beek\" et \"Haramt Ahebak\" ?", answer: "Warda al-Jazairia" },
  { type: "qcm", theme: "Musique", level: 1, question: "Quel est le nom de cette grande diva de la chanson kabyle, interprète du célèbre titre « Assa Nazha »?", options: ["Karima Benghane", "Taos Amrouche", "Malika Domrane"], answer: "Karima Benghane" },
  { type: "jesuis", theme: "Musique", level: 2, question: "Je suis l'artiste dont le célèbre tube \"El Ghorba\". Originaire de Boufarik, une banlieue d'Alger, j'ai commencé ma carrière en tant que break-dancer avant de me lancer dans la chanson en arabe, en français et en anglais.", answer: "Mok Saib" },
  { type: "jesuis", theme: "Musique", level: 3, question: "Pouvez-vous me dire le nom de l'artiste peintre et compositeur-interprète algérien qui a écrit et chanté le tube \"Yahya wlad bladi\" ainsi que \"Ouyahya bnat bladi\" ?", answer: "Rabah Deryassa" },
  { type: "qcm", theme: "Musique", level: 1, question: "Comment s'appelle l'interprète algérienne de musique traditionnelle et contemporaine qui chante \"Ghir Enta\"?", options: ["Chimène Badi", "Souad Massi", "Amel Bent"], answer: "Souad Massi" },
  { type: "jesuis", theme: "Musique", level: 2, question: "Je suis un musicien originaire de la ville de Béchar, et je suis connu sous le nom de scène Alla. Mon instrument de prédilection est le luth, que je joue avec passion et virtuosité.", answer: "Abdallah Abdelaziz" },
  { type: "jesuis", theme: "Musique", level: 3, question: "Qui est ce chanteur algérien de chaâbi qui a connu un succès fulgurant, notamment grâce à son tube \"chehilet laayani\" ?", answer: "Abdelkader Chaou" },
  { type: "qcm", theme: "Musique", level: 1, question: "Quel est le nom de ce chanteur et musicien algérien de Chaâbi dont la voix mélancolique a fait le succès du titre \"Echemâa\" ?", options: ["Cheb Titou", "Kamel Messaoudi", "El houari Dauphin"], answer: "Kamel Messaoudi" },
  { type: "jesuis", theme: "Musique", level: 2, question: "Quel est le nom de ce célèbre rappeur, connu pour son titre \"Tesla\" et son duo \"Moujat El Babour\" avec CHEMSOU freeklane, des œuvres qui ont suscité un grand engouement auprès du public en Algérie ?", answer: "Didin Canon 16" },
  { type: "jesuis", theme: "Musique", level: 3, question: "Quelle chanson algérienne a tellement cartonné sur Youtube que même les pyramides d'Egypte en sont jalouses? Avec pas moins de 355 millions de vues.", answer: "C'est la vie - Cheb Khaled" },
  { type: "qcm", theme: "Sports", level: 1, question: "Quel est le nom du premier club omnisports en Algérie et au Maghreb qui a vu le jour en 1894?", options: ["Racing Club Algérien", "Le Club des Joyeusetés d'Oran", "Olympique de Rouiba"], answer: "Le Club des Joyeusetés d'Oran" },
  { type: "jesuis", theme: "Sports", level: 2, question: "Je suis l'homme qui a inventé le geste portant mon nom. En finale de la Coupe d'Europe des clubs champions, j'ai inscrit le but égalisateur pour mon équipe contre le Bayern Munich, marquant ainsi l'histoire du football.", answer: "Rabah Madjer" },
  { type: "jesuis", theme: "Sports", level: 3, question: "Avec pas moins de 100 rencontres disputées, quel joueur de football peut se vanter d'avoir porté le maillot des verts (équipe nationale de football) le plus grand nombre de fois en matchs officiels ?", answer: "Lakhdar Belloumi" },
  { type: "qcm", theme: "Sports", level: 1, question: "Combien de fois l'équipe nationale de football algérienne a-t-elle obtenu le privilège de participer à la phase finale de la Coupe du monde ?", options: ["2 fois", "3 fois", "4 fois"], answer: "4 fois" },
  { type: "jesuis", theme: "Sports", level: 2, question: "Je suis une athlète algérienne , la première personne à avoir remporté une médaille d'or olympique pour l'Algérie, lors des Jeux de Barcelone en 1992, et j'ai également été double championne du monde du 1 500 mètres.", answer: "Hassiba Boulmerka" },
  { type: "jesuis", theme: "Sports", level: 3, question: "En quelle année l'équipe nationale d'Algérie de football remporte-t-elle sa première Coupe d'Afrique ?", answer: "En 1990. En cette année-là, l'Algérie a eu l'honneur d'être le pays hôte." },
  { type: "qcm", theme: "Sports", level: 1, question: "L'équipe algérienne de football a obtenu sa plus grande victoire à domicile  en 1973, lorsqu'elle \"croisa le fer\" avec l'équipe du Yémen du Sud. Quel en était le score?", options: ["7 à 1", "11 à 1", "15 à 1"], answer: "15 à 1" },
  { type: "jesuis", theme: "Sports", level: 2, question: "En tant qu'athlète algérien spécialisé dans les courses de demi-fond, j'ai remporté quatre titres de champion du monde du 1 500 mètres, mais j'ai surtout marqué l'histoire en devenant le premier athlète masculin algérien à remporter une médaille d'or aux Jeux Olympiques d'Atlanta en 1996.", answer: "Noureddine Morceli" },
  { type: "jesuis", theme: "Sports", level: 3, question: "Quel est le nageur algérien de renom, expert en nage libre, considéré comme le meilleur nageur de l'histoire de la natation algérienne ?", answer: "Salim Iles" },
  { type: "qcm", theme: "Sports", level: 1, question: "Qui était l'entraineur de l'équipe algérienne de football lors de sa participation  à la Coupe du monde de 2010, il qualifie l'Algérie pour le Mondial 2010 en battant l'Égypte ?", options: ["Rabah Saadane", "Abdel Djaadaoui", "Christian Gourcuff"], answer: "Rabah Saadane" },
  { type: "jesuis", theme: "Sports", level: 2, question: "Je suis un boxeur algérien ayant remporté une médaille de bronze aux championnats du monde de Sydney en 1991 et aux Jeux olympiques de Barcelone en 1992. J'ai également été médaillé d'or aux Jeux africains du Caire en 1991 ainsi qu'aux championnats d'Afrique en 1994.", answer: "Hocine Soltani" },
  { type: "jesuis", theme: "Sports", level: 3, question: "En quelle année le club algérien MC Alger  (Mouloudia d'Alger) a-t-il remporté la Ligue des Champions de la CAF pour la première fois?", answer: "En 1976" },
  { type: "qcm", theme: "Sports", level: 1, question: "Quelle est la position exacte qu'a atteinte l'équipe algérienne de football lors de la Coupe du monde 2014 ?", options: ["16 èmes de finale", "Demi-finale", "8 èmes de finale"], answer: "8 èmes de finale" },
  { type: "jesuis", theme: "Sports", level: 2, question: "Spécialiste des courses de demi-fond, j'ai remporté l'or  aux Jeux olympiques de Londres en 2012, lors du 1 500 mètres et j'ai décroché la médaille d'argent aux Jeux Olympiques de Rio de Janeiro en 2016 dans les épreuves de 800 et 1500 mètres.", answer: "Taoufik Makhloufi" },
  { type: "jesuis", theme: "Sports", level: 3, question: "Lors des huitièmes de finale de la Coupe du Monde 2014, l'équipe nationale de football a tenu tête à l'Allemagne, qui est devenue championne du monde. Quel était le score à la fin du match (après prolongations)?", answer: "Le score 2 à 1 (victoire de l'Allemagne)" },
  { type: "qcm", theme: "Sports", level: 1, question: "Quel talentueux journaliste sportif a exercé son métier pendant 19 ans pour la télévision algérienne et a présenté divers programmes télévisés dont \"Mala3eb el 3alam\",  avant de joindre BeIN Sports.", options: ["Issam Chaouali", "Hafid Derradji", "Raouf Ben Khelif"], answer: "Hafid Derradji" },
  { type: "jesuis", theme: "Sports", level: 2, question: "Je suis l'héro du match de demi-finale de la CAN 2019 entre l'Algérie et le Nigéria. Dans les dernières minutes du match, j'ai marqué le coup de grâce pour envoyer mon équipe en finale, suscitant ainsi la fierté et la joie de tout un pays.", answer: "Riyad Mahrez" },
  { type: "jesuis", theme: "Sports", level: 3, question: "L'équipe nationale de handball d'Algérie détient le record du nombre de titres consécutifs en Championnat d'Afrique. Combien de championnats d'Afrique consécutifs l'Algérie a-t-elle remportés durant la décennie des années 1980?", answer: "5 championnats d'Afrique consécutifs (1981,1983,1985,1987,1989)." },
  { type: "qcm", theme: "Sports", level: 1, question: "Quel est le club d'Algérie ayant remporté le plus grand nombre de titres officiels, avec un total impressionnant de 29 titres (à fin 2023)?", options: ["NAHD - Nasr Athletic Hussein Dey", "JSK - Jeunesse Sportive de Kabylie", "CRB - Chabab Riadhi Belouizdad"], answer: "JSK - Jeunesse Sportive de Kabylie" },
  { type: "jesuis", theme: "Sports", level: 2, question: "Je suis un nageur algérien. J’ai déjà remporté de nombreuses médaille dans différentes compétitions, dont de 27 ans, mort à fin, 2023.\nLors des 15eme jeux sportifs arabes, j’ai décroché 11, médaille d’or en natation et j’ai battu quatre records de lors de cette édition organisée en Algérie.", answer: "Jaoued Syoud" },
  { type: "jesuis", theme: "Sports", level: 3, question: "En 1964, lors des Jeux Olympiques de Tokyo, le drapeau de l'Algérie flotte pour la première fois. Quel est le nom du premier athlète algérien à se présenter aux Jeux Olympiques avec l'Algérie?", answer: "Mohamed Lazhari-Yamani" },
  { type: "qcm", theme: "Sports", level: 1, question: "Quelle équipe fut l'adversaire de l'Algérie lors de la finale de football des jeux méditerranéens de 1975, qui se déroula en Algérie ?", options: ["La France", "La Tunisie", "L'Italie"], answer: "La France" },
  { type: "jesuis", theme: "Sports", level: 2, question: "En tant qu'ancien joueur de handball algérien, j'ai remporté de nombreux titres nationaux et internationaux avec le MC Alger. J'ai été sélectionné 201 fois pour l'équipe nationale, ce qui fait de moi un des meilleurs joueurs de handball de ma génération.", answer: "Abdérazak Hamad" },
  { type: "jesuis", theme: "Sports", level: 3, question: "Quelle discipline a permis à l'Algérie d'inscrire son nom au tableau des médailles des Jeux Olympiques pour la première fois de son histoire?", answer: "La boxe - Les boxeurs Mustapha Moussa et Mohamed Zaoui offrent les premières médailles en 1984" },
  { type: "qcm", theme: "Sports", level: 1, question: "Dans le championnat d'Algérie de football, à quel club associe-t-on le groupe de fans \"Ouled El Bahdja \"?", options: ["CR Belouizdad", "USM Alger", "MC Alger"], answer: "USM Alger" },
  { type: "jesuis", theme: "Sports", level: 2, question: "Je suis une salle omnisports algérienne située à Alger, ayant une capacité d'accueil de plus de 8 000 spectateurs. J'accueille des manifestations sportives en intérieur telles que le handball, le basket-ball, le volley-ball, ainsi que de nombreuses compétitions internationales.", answer: "Salle \"Harcha Hassen\"" },
  { type: "jesuis", theme: "Sports", level: 3, question: "En quelle année la première équipe de football du FLN, rassemblant ses plus illustres représentants, tels que Mekhloufi, Kermali et Zitouni, a disputé le match de footbal où l'hymne national algérien, 'Quassaman', a été interprété pour la première fois?", answer: "En 1958, contre la Tunisie. Large victoire en faveur des Algériens." },
  { type: "qcm", theme: "Sports", level: 1, question: "Combien de fois l'équipe masculine algérienne de handball a-t-elle remporté le Championnat d'Afrique des nations ?", options: ["1 fois", "4 fois", "7 fois"], answer: "7 fois" },
  { type: "jesuis", theme: "Sports", level: 2, question: "Je suis le célèbre footballeur ayant fait partie de l'équipe légendaire du FLN pendant la guerre d'Algérie, reconnu comme une figure emblématique du football et je demeure à ce jour le deuxième meilleur buteur de l'AS Saint-Étienne, inscrivant ainsi mon nom dans les annales du club.", answer: "Rachid Makhloufi" },
  { type: "jesuis", theme: "Sports", level: 3, question: "Quel est le nom du premier président de la Fédération Algérienne de Rugby (FAR), fondée en 2015 et actuellement membre à part entière des instances internationales Rugby Afrique et World Rugby?", answer: "Sofiane Ben hassen" },
  { type: "qcm", theme: "Sports", level: 1, question: "Dans quelle formation de football Isaad Bourahli a-t-il achevé sa carrière sportive ?", options: ["MC Oran", "USM Alger", "ES Setif"], answer: "ES Setif" },
  { type: "jesuis", theme: "Sports", level: 2, question: "Je suis un ex-athlète algérien, ministre de la Jeunesse et des Sports, triple champion d'Afrique, médaillé de bronze aux Jeux Olympiques de Sydney en 2000 et détenteur du record national du saut en hauteur avec une performance de 2,34 mètres?", answer: "Abderrahmane Hammad" },
  { type: "jesuis", theme: "Sports", level: 3, question: "Comment s'appelle le nouveau stade de football situé dans la commune de Baraki, au sud-est d'Alger ? Il s'agit du premier stade en Algérie capable d'accueillir tous les matches organisés par la FIFA, y compris ceux de la coupe du monde.", answer: "Stade Nelson-Mandela" },
  { type: "qcm", theme: "Sports", level: 1, question: "Quel est le nom de la valeureuse boxeuse algérienne qui a décroché la médaille d'or lors des Jeux mediterraneens d'Oran 2022 ?", options: ["Imane Khelif", "Khadidja Timera", "Roumaysa Boualam"], answer: "Imane Khelif" },
  { type: "jesuis", theme: "Sports", level: 2, question: "Je suis un coureur cycliste algérien ayant remporté le tour d'Algérie sur route en 2021, ainsi que plusieurs places d'honneur sur différentes courses : médaillé de bronze au championnat africain en 2022, médaillé d'or au championnat arabe en individuel et en équipe en 2017.", answer: "Azzedine Lagab" },
  { type: "jesuis", theme: "Sports", level: 3, question: "Né en 2004, qui est ce prodigieux attaquant des Fennecs qui a marqué l'histoire en devenant le deuxième plus jeune joueur à porter le maillot de l'équipe nationale d'Algérie,  juste derrière l'emblématique Cherif El Ouazani ?", answer: "Badreddine Bouanani" },
  { type: "qcm", theme: "Sports", level: 1, question: "Comment appelle-t-on l'équipe nationale de football d'Algérie, surnom qui lui est affectueusement attribué ?", options: ["Les Ecureuils", "Les Fennecs", "Les Lions"], answer: "Les Fennecs" },
  { type: "jesuis", theme: "Sports", level: 2, question: "Je suis une judokate algérienne évoluant dans la catégorie poids mi-légers, ayant remporté des médailles mondiales et championne d'Afrique à plusieurs reprises, ainsi que médaillée olympique en 2008 lors des Jeux de Pékin.", answer: "Soraya Haddad" },
  { type: "jesuis", theme: "Sports", level: 3, question: "Quel est l'illustre boxeur algérien qui conquis le titre de champion d'Afrique amateur des poids mi-lourds en 1994 avant de passer professionnel en 1997.Ce champion WBB, doté d'un palmarès de 40 victoires, contre seulement 3 défaites et 1 match nul.", answer: "Mohamed Benguesmia" },
  { type: "qcm", theme: "Sports", level: 1, question: "Quel est le nom de ce lieu emblématique situé à Chéraga, chef-d'oeuvre architectural ayant été le théâtre de nombreuses manifestations sportives, concerts nationaux et internationaux ?", options: ["El-Djenane", "Nostrum", "La Coupole"], answer: "La Coupole" },
  { type: "jesuis", theme: "Sports", level: 2, question: "Je suis un footballeur international algérien évoluant au poste de milieu terrain offensif, ayant joué au Paris Saint-Germain où l'on me surnomme \"Mus\". J'ai inscrit 102 buts dans le championnat de France et me considère comme la première grande star du Paris Saint-Germain. En 2001, j'ai également été élu Fennec du siècle.", answer: "Mustapha Dahleb" },
  { type: "jesuis", theme: "Sports", level: 3, question: "Quel est le nom du célèbre handballeur algérien qui a marqué l'histoire de son pays en remportant plusieurs titres avec le Mouloudia Club d'Alger, ainsi que des victoires en équipe nationale et cumulant plus de 170 sélections et 110 buts en Équipe d'Algérie ?", answer: "Hichem Boudrali" },
  { type: "qcm", theme: "Sports", level: 1, question: "Quelle est la ville algérienne qui a eu l'honneur d'accueillir les Jeux africains en 1978 et en 2007?", options: ["Alger", "Oran", "Constantine"], answer: "Alger" },
  { type: "jesuis", theme: "Sports", level: 2, question: "Je suis une judokate algérienne, huit fois championne d'Afrique et première Africaine à avoir remporté la médaille d'or au Grand Slam de Paris. J'ai également été ancienne conseillère du ministre de la jeunesse et des sports, ministre délégué et ambassadrice à l'UNICEF.", answer: "Salima Souakri" },
  { type: "jesuis", theme: "Sports", level: 3, question: "Comment s'appelle le célèbre footballeur algérien qui était l'incontournable meneur de jeu du club de football de Saint-Étienne ? Dans le documentaire de l'illustre Éric Cantona, \"Les rebelles du football\", il expliqua son choix courageux de participer pacifiquement à la lutte pour l'indépendance de l'Algérie.", answer: "Rachid Mekhloufi" },
  { type: "qcm", theme: "Sports", level: 1, question: "Qui était ce célèbre entraîneur de football algérien qui a conduit fièrement l'équipe nationale à la victoire lors de la Coupe d'Afrique des nations de l'année 1990 ?", options: ["Abdelhamid Kermali", "Jean-Michel Cavalli", "Rabah Saadane"], answer: "Abdelhamid Kermali" },
  { type: "jesuis", theme: "Sports", level: 2, question: "Je suis l'éminent footballeur algérien qui s'est vu décerner le titre très convoité de meilleur joueur de la Coupe d'Afrique des nations en 2019. Depuis la saison 2019-2020, j'ai brillé en tant que milieu de terrain pour l'illustre AC Milan.", answer: "Ismaël Bennacer" },
  { type: "jesuis", theme: "Sports", level: 3, question: "Pouvez-vous m'indiquer le titre de la bande dessinée documentaire et historique relatant l'histoire de l'équipe de football du Front de libération nationale algérien ? L'intrigue de cet album se déroule entre 1945 et 1962.", answer: "\"Un maillot pour l'Algérie\", de Kris, Bertrand Galic et Javi Rey" },
  { type: "qcm", theme: "Sports", level: 1, question: "Pourriez-vous me dire le nom du stade olympique qui se trouve à Alger ?", options: ["Stade Ahmed Zabana", "Stade Nelson Mandela", "Stade du 5 Juillet 1962"], answer: "Stade du 5 Juillet 1962" },
  { type: "jesuis", theme: "Sports", level: 2, question: "Je suis l'illustre footballeur algérien qui a  popularisé la célèbre technique de \"La virgule - El-Ghoraf\" en Algérie,  deux décennies avant la légende brésilienne Ronaldinho. Mes exploits ont également conduit les Fennecs pour les Coupes du Monde de 1982 et 1986.", answer: "Salah Assad" },
  { type: "jesuis", theme: "Sports", level: 3, question: "À quel joueur d'origine algérienne fait référence la légende du football Di Stefano, avec cette citation ? \"Il domine le ballon, c'est un spectacle ambulant et il joue comme s'il avait des gants de soie à chaque pied. Il vaut la peine d'aller au stade, c'est l'un des meilleurs que j'aie jamais vu.\"", answer: "Zinédine Zidane" },
  { type: "qcm", theme: "Sports", level: 1, question: "Pour quelle equipe Madjer Rabah a-t-il joué lorsqu'il a décroché la victoire dans la compétition européenne majeure qu'est la Ligue des champions de l'UEFA en 1987 ?", options: ["Bayern Munich", "FC Porto", "Benfica Lisbonne"], answer: "FC Porto" },
  { type: "jesuis", theme: "Sports", level: 2, question: "Je suis l'illustre footballeur qui fut couronné Ballon d'Or africain en 1981,Je suis reconnu comme le meilleur joueur que l'Algérie ait jamais produit, ayant été à l'avant-garde de l'introduction de la passe aveugle dans le jeu.", answer: "Lakhdar Belloumi" },
  { type: "jesuis", theme: "Sports", level: 3, question: "Les 19èmes Jeux méditerranéens se sont tenus à Oran, en 2022. l'Algérie pays hôte s'est distinguée avec un total de 53 médailles, se hissant ainsi la quatrième place du classement général. Qui a fini en tête de ce classement ?", answer: "L'Italie, avec un total de 159 médailles, dont 48 en or." },
  { type: "qcm", theme: "Sports", level: 1, question: "Quel est le sélectionneur de l'Algérie de 2011 à 2014, qui pour la première fois l'a qualifié pour les 8e de finale de la Coupe du monde:", options: ["Vahid Halilhodžić", "Rabah Saâdane", "Nacer Sandjak"], answer: "Vahid Halilhodžić" },
  { type: "jesuis", theme: "Sports", level: 2, question: "On me surnomme l'héritière de Boulmerka, car j'ai offert à l'Algérie une nouvelle médaille d'or au 1500m lors des JO 2000 à Sydney, perpétuant ainsi la tradition algérienne dans cette discipline.", answer: "Nouria Benida-Merah" },
  { type: "jesuis", theme: "Sports", level: 3, question: "Quel est le nom de l'entraîneur polonais qui a formé avec Mahieddine Khalef le duo à la tête de l'équipe de la Jeunesse Électronique de Tizi-Ouzou, \"Jumbo JET\", et qui a permis à cette équipe de dominer le football algérien et international pendant une décennie ?", answer: "Stefan Zywotko" },
  { type: "qcm", theme: "Sports", level: 1, question: "Quel est le dirigeant sportif algérien, qui a été président de la Fédération algérienne de football de 2001 à 2005, puis de 2009 à 2017:", options: ["Khereddine Zetchi", "Mohamed Raouraoua", "Djahid Zefizef"], answer: "Mohamed Raouraoua" },
  { type: "jesuis", theme: "Sports", level: 2, question: "Je suis un footballeur international algérien, reconverti par la suite entraîneur. J'ai été joueur de  Marseille de 2000 à 2003, puis de  Manchester City. Je suis aussi  le premier lauréat de l’histoire du Ballon d’Or algérien l", answer: "Djamel Belmadi" },
  { type: "jesuis", theme: "Sports", level: 3, question: "Qui détient le record du meilleur buteur de l'histoire du championnat d'Algérie de football avec un impressionnant total de 131 buts marqués ?", answer: "Hacène Lalmas" },
];